/**
 * Connect to a Profiler server over WebSocket.
 * @param url - WebSocket URL (e.g., "ws://localhost:9000")
 * @returns A connected ProfilerClient instance
 */
export async function connectProfiler(
  url: string,
  options: SessionTransportOptions = {},
): Promise<ProfilerClient> {
  const established = await session.initiator(wsConnector(url), { ...options, metadata: voxServiceMetadata("Profiler") });
  return new ProfilerClient(established.rootConnection().caller());
}

